function getModule(fullText, moduleName) {
  // Busca por ### @MODULE: NOME ... até ... ### @END_MODULE
  const regex = new RegExp(`### @MODULE:\\s*${moduleName}[\\s\\S]*?([\\s\\S]*?)### @END_MODULE`, 'i');
  const match = fullText.match(regex);
  return match ? match[1].trim() : null;
}

const input = $json;
const usuario = input.pessoa;
const fullTextPrompt = input.prompt.conteudo;
let baseContent = "";
let promptMontado = "";
let moduloAtivo = "";
let modulosSolicitados = [];
let modulosCarregadosLog = [];


// 1. Validação de Segurança
if (!input.prompt || !input.prompt.conteudo) {
  throw new Error("ERRO CRÍTICO: Texto do Prompt Mestre não foi carregado.");
}


moduloAtivo = usuario.contexto_memoria.actionDataContext.faseCore || "ROTEADOR_CENTRAL";
modulosSolicitados = [moduloAtivo];

// PASSO A: Carregar o Sistema Operacional (BASE)
baseContent = getModule(fullTextPrompt, 'BASE') ;

if (baseContent) {
    promptMontado += baseContent;
    modulosCarregadosLog.push("BASE");
} else {
    // Fallback de segurança se o arquivo de texto estiver corrompido
    promptMontado += "ATENÇÃO: Módulo BASE não encontrado. Verifique o arquivo de prompt.";
}


// PASSO B: Carregar os Modulos Solicitados
if (Array.isArray(modulosSolicitados) && modulosSolicitados.length > 0) {
  for (const nomeModulo of modulosSolicitados) {
      moduloAtivo = nomeModulo;
      const content = getModule(fullTextPrompt, nomeModulo);
      if (content) {
          promptMontado += `\n\n--- 📍 MÓDULO ATIVO: ${nomeModulo} ---\n` + content;
          modulosCarregadosLog.push(nomeModulo);
      } else {
          // Log silencioso se o módulo pedido não existir no arquivo de texto
          modulosCarregadosLog.push(`ERRO_404: ${nomeModulo}`);
      }
  }
} else {
  // Se a lista vier vazia, carregamos um módulo default de segurança (opcional)
  // Aqui optamos por não carregar nada extra, deixando apenas a BASE falar.
  modulosCarregadosLog.push("NENHUM_MODULO_EXTRA");
}


const promptParts = {
  dynamicPrompt: promptMontado,
  debug: {
