// Função de Parsing de JSON Segura e Reutilizável
const parseActionData = (jsonText) => {
    try {
      return JSON.parse(jsonText);
    } catch (error) {
      // 1. Tenta encontrar o bloco de código JSON (```json ... ```)
      const jsonStart = jsonText.indexOf('```json') + 7;
      //const jsonStart = jsonText.indexOf('```json') + 1;

      const jsonEnd = jsonText.lastIndexOf('```');

      if (jsonStart === 6 || jsonEnd === -1 || jsonStart >= jsonEnd) {
        return { error: `JSON block not found` };
      }

      // 2. Extrai e Limpa o JSON String
      const jsonString = jsonText.substring(jsonStart, jsonEnd).trim();

      // 3. Converte para Objeto JavaScript
      const parsedData = JSON.parse(jsonString);
      //const parsedData = jsonString;
      return parsedData;
    }

};


